text:
{
  "formal_minutes": {
    "confirmed_decisions": [
      {
        "item": "릴리스 공개 목표일은 화요일/수요일이 아니라 '금요일 15:00 KST'로 확정되었고, 조건은 스모크 테스트 통과이다.",
        "source": "회의 원문"
      },
      {
        "item": "packageName 불일치가 발생할 때는 `smoke-theme-pack.mjs`에서 무조건 무시하지 않고, 우선 패키지 설정을 확인한다. 계약 자체가 잘못된 경우에만 스크립트 재검토한다.",
        "source": "회의 원문"
      },
      {
        "item": "수요일은 내부 Stretch Goal로만 유지되고, 공개 릴리스 목표와는 분리한다.",
        "source": "회의 원문"
      }
    ],
    "rejected_proposals": [
      {
        "item": "Hara의 `smoke-theme-pack.mjs`에서 packageName mismatch를 무시하도록 변경하는 제안은 기각됨.",
        "source": "회의 원문"
      },
      {
        "item": "스모크 테스트 미통과 상태에서 수요일 즉시 공개 출시를 확정하는 안은 기각됨.",
        "source": "회의 원문"
      }
    ],
    "internal_stretch_goals": [
      {
        "item": "수요일 공개 준비 목표",
        "status": "내부 stretch goal(비공개 공개 목표 아님)"
      },
      {
        "item": "README 설치 단계 검토를 가능하면 목요일까지 수행",
        "status": "권고/희망사항(확정 액션 아님)"
      }
    ],
    "risks": [
      {
        "item": "잘못된 tarball 경로 사용 시 릴리스 지연 가능성",
        "source": "회의 원문"
      },
      {
        "item": "README 설치 단계가 오래되어 릴리스 노트가 사용자에게 오해를 줄 수 있음",
        "source": "회의 원문"
      }
    ],
    "open_questions": [
      {
        "item": "최종 릴리스 승인 권한자는 누구인가?"
      },
      {
        "item": "릴리스 노트에 내부 수요일 stretch goal(예: 예상 완료일)을 기재할지 여부"
      }
    ],
    "non_decisions": [
      {
        "item": "고객/외부 파트너 명칭, 예산, 보안 사고, 프로덕션 장애, 법무 승인, 담당자, 최종 마감일(공개 타임라인 외)은 회의에서 언급되지 않음."
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트 재실행",
      "due": "2026-05-15 10:00 KST",
      "status": "confirmed",
      "source_certainy": "confirmed"
    },
    {
      "owner": "Doyun",
      "task": "`action_items.md`에 실패 트리아지 노트 작성",
      "due": "2026-05-15 12:00 KST",
      "status": "confirmed",
      "source_certainy": "confirmed"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 후 생성 tarball 경로 확인",
      "due": "미정",
      "status": "confirmed",
      "source_certainy": "confirmed_partial"
    },
    {
      "owner": "미할당",
      "task": "README 설치 단계 검토 수행",
      "due": "미정",
      "status": "proposed",
      "source_certainy": "low"
    }
  ],
  "followup_note": {
    "what_to_check_next": [
      "스모크 테스트 결과(금요일 10:00 KST) 공지 수신 후, 결과 통과 여부를 기준으로 공개 릴리스(금요일 15:00 KST) 가능성 재확인.",
      "Hara의 tarball 경로 확인 결과 반영 후, 경로 이슈 발생 시 원인(패키지 설정/계약 정의/스크립트) 분기 체크.",
      "README 설치 단계 검토 담당자 및 실행 유무 확인(목요일 검토 권고가 실행되었는지)."
    ],
    "what_not_to_invent": [
      "고객명/파트너명, 예산, 보안 사건, 장애, 법무 승인, 오너(부재 데이터), 추가 마감일 등 회의에서 언급되지 않은 사실을 추가하지 않는다.",
      "수요일이 최종 공개 릴리스 확정인지 또는 승인권자 관련 임의 추정을 넣지 않는다."
    ]
  },
  "non_invention_rules": [
    "회의 텍스트에 명시되지 않은 고객, 예산, 보안 이슈, 장애, 법무 승인, 오너, 데드라인(미할당 항목)을 생성하지 않는다.",
    "미확인/미확정 항목(승인권자, 내부 stretch goal 공개 표기 여부, 담당자 미지정 항목)은 추정 없이 open question 또는 미확정 상태로만 기록한다.",
    "날짜/시간은 원문에 나온 값(금요일 15:00, 금요일 10:00, 금요일 12:00, 수요일 stretch)만 사용하고, 다른 일정 값을 추가하지 않는다.",
    "‘action_items.md’ 기록은 Doyun이 실행할 작업으로만 확정하고, 다른 사람이 작성했다는 임의 소유권 주입을 피한다.",
    "이 문서는 inline public-safe synthetic fixture 범위를 벗어나지 않도록 순수 회의 기록 기반으로만 작성한다."
  ]
}
